<span class="line"><span style="color:#171717;font-weight:bold">    if</span><span style="color:#6E6961">(</span><span style="color:#171717">n </span><span style="color:#171717;font-weight:bold">&#x3C;</span><span style="color:#171717"> m</span><span style="color:#6E6961">)</span><span style="color:#171717;font-weight:bold"> return</span><span style="color:#3D3A35"> 0</span><span style="color:#6E6961">;</span><span style="color:#76716A;font-style:italic"> //长度不符合标准</span></span>
